import { Row } from 'react-bootstrap';
import Accordion from 'react-bootstrap/Accordion';

function QADropdown() {
  return (
    <Row>
    <Accordion>
      <Accordion.Item eventKey="0">
        <Accordion.Header>
        <div className='m-auto'>
            السؤال الأول
            </div>
            </Accordion.Header>
        <Accordion.Body>
          الإجابة الأولى
        </Accordion.Body>
        <Accordion.Body>
          الإجابة الثانية
        </Accordion.Body>
      </Accordion.Item>

    </Accordion>
    </Row>
  );
}

export default QADropdown;
